/**
 * @packageDocumentation
 * Synchronize or validate the README rules table from canonical rule metadata.
 */
// @ts-check

import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

// @ts-ignore -- Generated by the build; this script intentionally validates built output.
import builtPlugin from "../dist/plugin.js";
const stylelint2ConfigMetadataByName = {
    all: { icon: "🟣" },
    configs: { icon: "🛠️" },
    recommended: { icon: "🟡" },
    stylesheets: { icon: "🎨" },
};
const stylelint2ConfigNamesByReadmeOrder = [
    "recommended",
    "stylesheets",
    "configs",
    "all",
];
const stylelint2ConfigReferenceToName = {
    "stylelint2.configs.all": "all",
    "stylelint2.configs.configs": "configs",
    "stylelint2.configs.recommended": "recommended",
    "stylelint2.configs.stylesheets": "stylesheets",
};

const rulesSectionHeading = "## Rules";

/** @param {string} markdown */
const detectLineEnding = (markdown) =>
    markdown.includes("\r\n") ? "\r\n" : "\n";

/** @param {string} markdown */
const getRulesSectionBounds = (markdown) => {
    const startOffset = markdown.indexOf(rulesSectionHeading);

    if (startOffset < 0) {
        throw new Error("README.md is missing the '## Rules' section heading.");
    }

    const nextHeadingOffset = markdown.indexOf(
        "\n## ",
        startOffset + rulesSectionHeading.length
    );

    return {
        endOffset: nextHeadingOffset < 0 ? markdown.length : nextHeadingOffset,
        startOffset,
    };
};

/** @param {string} markdown */
export const extractReadmeRulesSection = (markdown) => {
    const { endOffset, startOffset } = getRulesSectionBounds(markdown);

    return markdown.slice(startOffset, endOffset);
};

/** @param {readonly string[] | string | undefined} configs */
const normalizeConfigNames = (configs) => {
    const values = Array.isArray(configs) ? configs : [configs];
    const normalized = [];

    for (const value of values) {
        if (typeof value !== "string") {
            continue;
        }

        if (Object.hasOwn(stylelint2ConfigReferenceToName, value)) {
            const referenceKey =
                /** @type {keyof typeof stylelint2ConfigReferenceToName} */ (
                    value
                );

            normalized.push(stylelint2ConfigReferenceToName[referenceKey]);
        }
    }

    return [...new Set(normalized)];
};

/** @param {{ meta?: { fixable?: string } }} ruleModule */
const getRuleFixIndicator = (ruleModule) =>
    ruleModule.meta?.fixable === "code" ? "🔧" : "—";

/** @param {{ meta?: { docs?: { configs?: readonly string[] | string } } }} ruleModule */
const getPresetIndicator = (ruleModule) => {
    const configNames = new Set(
        normalizeConfigNames(ruleModule.meta?.docs?.configs)
    );

    const icons = [];

    for (const configName of stylelint2ConfigNamesByReadmeOrder) {
        if (!configNames.has(configName)) {
            continue;
        }

        const metadataKey =
            /** @type {keyof typeof stylelint2ConfigMetadataByName} */ (
                configName
            );

        icons.push(stylelint2ConfigMetadataByName[metadataKey].icon);
    }

    return icons.join(" ");
};

/** @param {[
    string,
    {
        meta: {
            docs: { url: string; configs?: readonly string[] | string };
            fixable?: string;
        };
    },
]} entry */
const toRuleTableRow = ([ruleName, ruleModule]) =>
    `| [\`${ruleName}\`](${ruleModule.meta.docs.url}) | ${getRuleFixIndicator(ruleModule)} | ${getPresetIndicator(ruleModule)} |`;

/** @param {Readonly<
    Record<
        string,
        {
            meta: {
                docs: { url: string; configs?: readonly string[] | string };
                fixable?: string;
            };
        }
    >
>} rules */
export const generateReadmeRulesSectionFromRules = (rules) => {
    const ruleEntries = Object.entries(rules).toSorted(([left], [right]) =>
        left.localeCompare(right)
    );

    return [
        "## Rules",
        "",
        "- `Fix` legend:",
        "  - `🔧` = autofixable",
        "  - `—` = report only",
        "- `Preset key` legend:",
        "  - `🟡` = `stylelint2.configs.recommended`",
        "  - `🎨` = `stylelint2.configs.stylesheets`",
        "  - `🛠️` = `stylelint2.configs.configs`",
        "  - `🟣` = `stylelint2.configs.all`",
        "",
        "| Rule | Fix | Preset key |",
        "| --- | :-: | :-- |",
        ...ruleEntries.map(toRuleTableRow),
        "",
    ].join("\n");
};

export const syncReadmeRulesTable = async ({ writeChanges = false } = {}) => {
    const readmePath = resolve("README.md");
    const readmeMarkdown = await readFile(readmePath, "utf8");
    const lineEnding = detectLineEnding(readmeMarkdown);
    const expectedSection = generateReadmeRulesSectionFromRules(
        builtPlugin.rules
    )
        .replace(/\n/gv, lineEnding)
        .trimEnd();
    const { endOffset, startOffset } = getRulesSectionBounds(readmeMarkdown);
    const currentSection = readmeMarkdown
        .slice(startOffset, endOffset)
        .trimEnd();

    if (currentSection === expectedSection) {
        return { changed: false };
    }

    if (!writeChanges) {
        throw new Error(
            "README rules table is out of sync with plugin metadata."
        );
    }

    const updatedReadme = `${readmeMarkdown.slice(0, startOffset)}${expectedSection}${readmeMarkdown.slice(endOffset)}`;
    await writeFile(readmePath, updatedReadme, "utf8");

    return { changed: true };
};

if (import.meta.url === new URL(process.argv[1], "file:").href) {
    await syncReadmeRulesTable({
        writeChanges: process.argv.includes("--write"),
    });
}
